if ((condition1 && condition2)
        || (condition3 && condition4)    // line wrap with bigger indentation
        ||!(condition5 && condition6)) { // line wrap with bigger indentation
  field.doSomething()                    // basic offset
      .doSomething()                     // line wrap
      .doSomething( c -> {               // line wrap
        return c.doSome();               // basic offset
      });
}

class Example1 {
    int a;                      // ok, basicOffset = 4

    void method() {
        int b = 0;              // ok, basicOffset = 4
    }

    void method2()
            throws Exception {  // ok, throwsIndent = 4
        switch (a) {
            case 1:             // ok, caseIndent = 4
                break;
        }
    }

    int[] values = {
        1, 2, 3                 // ok, arrayInitIndent = 4
    };
}

class Example2 {
    void method(int x) {
        switch (x) {
        case 1:             // ok, caseIndent = 0 (same level as switch body)
            break;
        case 2:             // ok
            break;
            case 3:         // violation, 'level 12, expected level should be 8'
            break;
        }
    }
}

class Example3 {
    boolean x, y;

    void method(int a,
        int b) {            // ok, lineWrappingIndentation=4 from method
        if (x
            && y) {         // ok, lineWrappingIndentation=4 from 'if'
            method(a, b);
        }
    }

    void method2(int a,
                 int b) {   // violation, 'level 17, expected level should be 8'
        if (x
                && y) {     // violation, 'level 16, expected level should be 12'
            method2(a, b);
        }
    }
}

class Example4 {
      int a;               // violation, 'level 6, expected level should be 4'

    void method() {
        int b = 0;         // ok
          int c = 1;       // violation, 'level 10, expected level should be 8'
    }
}

class Example5 {
  int a;                  // ok, basicOffset = 2

  void method() {
    int b = 0;            // ok, basicOffset = 2
      int c = 1;          // violation, 'level 6, expected level should be 4'
  }
}

class Example6 {
    boolean x, y;

    void method(int a,
            int b) {        // ok, lineWrappingIndentation = 8
        if (x
                && y) {     // ok, lineWrappingIndentation = 8
        }
    }

    void method2(int a,
        int b) {            // violation, 'level 8, expected level should be 12'
        if (x
            && y) {         // violation, 'level 12, expected level should be 16'
        }
    }
}

class Example7 {
    String field = "example";                  // basicOffset
    int[] values = {                           // basicOffset
        10,
        20,
        30
    };

    void processValues()
        throws Exception { // violation, ''throws' has incorrect indentation'
        handleValue("Test String", 42);          // basicOffset
    }

    void handleValue(String aFooString,
                     int aFooInt) {             // indent:8 ; expected: > 4;

        boolean cond1,cond2,cond3,cond4,cond5,cond6;
        cond1=cond2=cond3=cond4=cond5=cond6=false;

        if (cond1
            || cond2) {
            field = field.toUpperCase()
                .concat(" TASK");
        }

        if ((cond1 && cond2)
                || (cond3 && cond4)          // ok, lineWrappingIndentation
                || !(cond5 && cond6)) {      // ok, lineWrappingIndentation
            field.toUpperCase()
                 .concat(" TASK")             // ok, lineWrappingIndentation
                 .chars().forEach(c -> {      // ok, lineWrappingIndentation
                     System.out.println((char) c);
                 });
        }
    }

    void demonstrateSwitch()
            throws Exception {               // ok, throwsIndent is 8
        switch (field) {
            case "EXAMPLE": processValues();                        // caseIndent
            case "COMPLETED": handleValue("Completed Case", 456);   // caseIndent
        }
    }
}

class Example8 {
    int[] values1 = {
      10,                 // ok, arrayInitIndent = 2 (col 6 = array col 4 + 2)
      20,
      30
    };

    int[] values2 = {
  10                      // violation, 'level 2, expected level should be one of'
    };
}

class Example9 {
    void method()
      {               // ok, braceAdjustment = 2 (col 6 = method col 4 + braceAdj 2)
      }               // ok, closing brace at col 6

    void method2()
    {                 // violation, 'level 4, expected level should be 6'
    }                 // violation, 'level 4, expected level should be 6'
}
